<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Maze Bot Exploration</title>
<style>
  body { font-family: sans-serif; margin: 0; padding: 1rem; background: #f0f0f0; }
  #controls { display: flex; gap: 1rem; align-items: center; margin-bottom: 1rem; }
  #maze { position: relative; width: 400px; height: 400px; background: #fff; border: 2px solid #333; box-shadow: 0 2px 8px rgba(0,0,0,0.1); }
  #maze canvas { position: absolute; top: 0; left: 0; width: 100%; height: 100%; }
  .bot { position: absolute; width: 12px; height: 12px; border-radius: 50%; transform: translate(-50%, -50%); pointer-events: none; transition: transform 0.2s linear; will-change: transform; }
  label { font-weight: bold; }
</style>
</head>
<body>
<div id="controls">
  <button id="reset">Reset</button>
  <label>Timer: <span id="timer">0</span></label>
  <label>Completed: <span id="completed">0</span>/24</label>
</div>
<div id="maze"><canvas id="mazeCanvas"></canvas></div>

<script>
/* ========== Seeded RNG (mulberry32) ========== */
function createRNG(seed) {
  let t = seed >>> 0;
  return function() {
    t += 0x6D2B79F5;
    let res = Math.imul(t ^ (t >>> 15), t | 1);
    res ^= res + Math.imul(res ^ (res >>> 7), res | 61);
    return ((res ^ (res >>> 14)) >>> 0) / 4294967296;
  };
}

/* ========== Maze Generation (Perfect Maze via Randomized DFS) ========== */
function generateMaze(rows, cols, rng) {
  const cells = Array.from({length: rows}, () => Array.from({length: cols}, () => ({
    walls: {n: true, e: true, s: true, w: true},
    visited: false
  })));
  const stack = [{r: 0, c: 0}];
  cells[0][0].visited = true;
  const dirs = [
    {dr: -1, dc: 0, wall: 'n', opp: 's'},
    {dr: 0, dc: 1, wall: 'e', opp: 'w'},
    {dr: 1, dc: 0, wall: 's', opp: 'n'},
    {dr: 0, dc: -1, wall: 'w', opp: 'e'}
  ];
  while (stack.length) {
    const cur = stack[stack.length - 1];
    const neighbors = [];
    for (const d of dirs) {
      const nr = cur.r + d.dr, nc = cur.c + d.dc;
      if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && !cells[nr][nc].visited) {
        neighbors.push({d, nr, nc});
      }
    }
    if (neighbors.length) {
      const idx = Math.floor(rng() * neighbors.length);
      const {d, nr, nc} = neighbors[idx];
      cells[cur.r][cur.c].walls[d.wall] = false;
      cells[nr][nc].walls[d.opp] = false;
      cells[nr][nc].visited = true;
      stack.push({r: nr, c: nc});
    } else {
      stack.pop();
    }
  }
  return cells;
}

/* ========== Game State ========== */
const ROWS = 15, COLS = 15;
const SPAWN = {r: 0, c: 0};
const EXIT = {r: ROWS - 1, c: COLS - 1};

const game = {
  elapsed: 0,
  finished: false,
  size: {rows: ROWS, cols: COLS},
  spawn: SPAWN,
  exit: EXIT,
  walls(r, c) {
    const cell = this._maze[r][c];
    return {n: cell.walls.n, e: cell.walls.e, s: cell.walls.s, w: cell.walls.w};
  },
  bots: [],
  _maze: null,
  _rng: null,
  _seed: null,

  reset(seed) {
    this._seed = (seed !== undefined) ? seed : Math.floor(Math.random() * 0x100000000);
    this._rng = createRNG(this._seed);
    this._maze = generateMaze(ROWS, COLS, this._rng);
    this.elapsed = 0;
    this.finished = false;

    // Create 24 bots with distinct direction orders
    this.bots = [];
    for (let i = 0; i < 24; i++) {
      const botRng = createRNG(this._seed + i + 1);
      const dirOrder = [0,1,2,3].sort(() => botRng() - 0.5); // 0:N,1:E,2:S,3:W
      const hue = (i * 360 / 24) | 0;
      this.bots.push({
        id: i,
        color: `hsl(${hue}, 80%, 50%)`,
        path: [{r: SPAWN.r, c: SPAWN.c}],
        deadEnds: [],
        finishTick: null,
        // internal
        _current: {r: SPAWN.r, c: SPAWN.c},
        _prev: null,
        _visited: new Set([`${SPAWN.r},${SPAWN.c}`]),
        _deadEndsSet: new Set(),
        _forwardStack: [{r: SPAWN.r, c: SPAWN.c}],
        _dirOrder: dirOrder,
        _finished: false
      });
    }
    drawMaze();
    updateBotPositions();
    updateUI();
  },

  tick(n) {
    if (this.finished) return;
    for (let step = 0; step < n; step++) {
      if (this.finished) break;
      let anyMoving = false;
      for (const bot of this.bots) {
        if (bot._finished) continue;
        anyMoving = true;
        stepBot(bot);
      }
      this.elapsed++;
      // Check if all bots finished
      if (this.bots.every(b => b._finished)) {
        this.finished = true;
      }
      updateBotPositions();
      updateUI();
    }
  }
};

/* ========== Bot Step (Tremaux/DFS Exploration) ========== */
const DIRS = [
  {dr: -1, dc: 0, wall: 'n'}, // N
  {dr: 0, dc: 1, wall: 'e'},  // E
  {dr: 1, dc: 0, wall: 's'},  // S
  {dr: 0, dc: -1, wall: 'w'}  // W
];

function stepBot(bot) {
  const cur = bot._current;
  // Check exit
  if (cur.r === EXIT.r && cur.c === EXIT.c) {
    bot._finished = true;
    bot.finishTick = game.elapsed + 1; // this tick will complete
    return;
  }

  const cell = game._maze[cur.r][cur.c];
  // Try unvisited neighbors in bot's preferred order
  for (const dirIdx of bot._dirOrder) {
    const d = DIRS[dirIdx];
    if (!cell.walls[d.wall]) {
      const nr = cur.r + d.dr, nc = cur.c + d.dc;
      const key = `${nr},${nc}`;
      if (!bot._visited.has(key) && !bot._deadEndsSet.has(key)) {
        // Move forward
        bot._prev = cur;
        bot._current = {r: nr, c: nc};
        bot._visited.add(key);
        bot._forwardStack.push(bot._current);
        bot.path.push({r: nr, c: nc});
        return;
      }
    }
  }
  // No unvisited neighbor -> backtrack
  if (bot._forwardStack.length > 1) {
    // Mark current cell as dead end
    const deadKey = `${cur.r},${cur.c}`;
    if (!bot._deadEndsSet.has(deadKey)) {
      bot._deadEndsSet.add(deadKey);
      bot.deadEnds.push({r: cur.r, c: cur.c});
    }
    bot._forwardStack.pop(); // remove current
    bot._prev = cur;
    bot._current = bot._forwardStack[bot._forwardStack.length - 1];
    bot.path.push({r: bot._current.r, c: bot._current.c});
  }
  // If stack length is 1, we're at start with nowhere to go (shouldn't happen before exit)
}

/* ========== Rendering ========== */
const canvas = document.getElementById('mazeCanvas');
const ctx = canvas.getContext('2d');
const CELL_SIZE = 400 / COLS; // 400px canvas
const WALL_THICKNESS = 2;

function drawMaze() {
  canvas.width = 400;
  canvas.height = 400;
  ctx.strokeStyle = '#000';
  ctx.lineWidth = WALL_THICKNESS;
  ctx.lineCap = 'square';

  for (let r = 0; r < ROWS; r++) {
    for (let c = 0; c < COLS; c++) {
      const x = c * CELL_SIZE;
      const y = r * CELL_SIZE;
      const cell = game._maze[r][c];
      if (cell.walls.n) { ctx.beginPath(); ctx.moveTo(x, y); ctx.lineTo(x + CELL_SIZE, y); ctx.stroke(); }
      if (cell.walls.e) { ctx.beginPath(); ctx.moveTo(x + CELL_SIZE, y); ctx.lineTo(x + CELL_SIZE, y + CELL_SIZE); ctx.stroke(); }
      if (cell.walls.s) { ctx.beginPath(); ctx.moveTo(x + CELL_SIZE, y + CELL_SIZE); ctx.lineTo(x, y + CELL_SIZE); ctx.stroke(); }
      if (cell.walls.w) { ctx.beginPath(); ctx.moveTo(x, y + CELL_SIZE); ctx.lineTo(x, y); ctx.stroke(); }
    }
  }
  // Mark exit visually (optional)
  ctx.fillStyle = '#0f0';
  ctx.fillRect(EXIT.c * CELL_SIZE + 2, EXIT.r * CELL_SIZE + 2, CELL_SIZE - 4, CELL_SIZE - 4);
}

function updateBotPositions() {
  const mazeEl = document.getElementById('maze');
  // Remove old bot elements
  document.querySelectorAll('.bot').forEach(el => el.remove());
  for (const bot of game.bots) {
    const el = document.createElement('div');
    el.className = 'bot';
    el.style.background = bot.color;
    el.style.border = '1px solid #000';
    el.style.boxSizing = 'border-box';
    const cur = bot._current;
    const x = (cur.c + 0.5) * CELL_SIZE;
    const y = (cur.r + 0.5) * CELL_SIZE;
    el.style.transform = `translate(${x}px, ${y}px)`;
    mazeEl.appendChild(el);
  }
}

function updateUI() {
  document.getElementById('timer').textContent = game.elapsed;
  const completed = game.bots.filter(b => b.finishTick !== null).length;
  document.getElementById('completed').textContent = completed;
}

/* ========== Event Listeners ========== */
document.getElementById('reset').addEventListener('click', () => {
  game.reset();
});

/* ========== Initialize ========== */
game.reset(); // random seed

// Expose API
window.game = {
  tick: (n) => game.tick(n),
  reset: (seed) => game.reset(seed),
  get elapsed() { return game.elapsed; },
  get size() { return game.size; },
  get spawn() { return game.spawn; },
  get exit() { return game.exit; },
  walls: (r, c) => game.walls(r, c),
  get bots() { return game.bots.map(b => ({
    path: b.path,
    deadEnds: b.deadEnds,
    finishTick: b.finishTick
  })); }
};
</script>
</body>
</html>
